(window.webpackJsonp=window.webpackJsonp||[]).push([[440],{1067:function(r,n){r.exports="\x3c!-- \r\ntitle: 12-CSS操作\r\nsort: \r\n--\x3e \r\n# CSS进阶\r\n\r\n## 定位`position`\r\n\r\n### static\r\n\r\n> 固定位置，不随窗口而移动\r\n\r\n```css\r\ndiv {\r\n    position: static;\r\n    border: 3px solid #73AD21;\r\n}\r\n```\r\n\r\n### fixed\r\n\r\n> 相对浏览器窗口为固定位置\r\n\r\n```css\r\np\r\n{\r\n\tposition:fixed;\r\n\ttop:30px;\r\n\tright:5px;\r\n}\r\n```\r\n\r\n### relative\r\n\r\n> 相对正常位置的移动\r\n>\r\n> ![image-20200726100439709](https://gitee.com/nmdfzf404/Image-hosting/raw/master/20200726100446.png)\r\n\r\n```css\r\nh2\r\n{\r\n    position:relative;\r\n    left:-20px;\r\n}\r\nh2\r\n{\r\n    position:relative;\r\n    left:20px;\r\n}\r\n```\r\n\r\n### absolute\r\n\r\n> 相对于已定位的父元素，假如没有，则相对于html\r\n>\r\n> `position:absolute;`\r\n\r\n### sticky\r\n\r\n> 粘贴定位，元素不会出页面。\r\n>\r\n> `position: sticky;`\r\n\r\n## Overflow\r\n\r\n> 页面内滚动条\r\n>\r\n> | 值      | 描述                                                     |\r\n> | :------ | :------------------------------------------------------- |\r\n> | visible | 默认值。内容不会被修剪，会呈现在元素框之外。             |\r\n> | hidden  | 内容会被修剪，并且其余内容是不可见的。                   |\r\n> | scroll  | 内容会被修剪，但是浏览器会显示滚动条以便查看其余的内容。 |\r\n> | auto    | 如果内容被修剪，则浏览器会显示滚动条以便查看其余的内容。 |\r\n> | inherit | 规定应该从父元素继承 overflow 属性的值。                 |\r\n\r\n```css\r\ndiv {\r\n    width: 200px;\r\n    height: 50px;\r\n    background-color: #eee;\r\n    overflow: auto;\r\n}\r\n```\r\n\r\n## 浮动\r\n\r\n> 在元素的水平方向浮动，不能上下\r\n>\r\n> `float:right;`\r\n>\r\n> 清除： `clear:both`\r\n\r\n## 布局\r\n\r\n### 对齐\r\n\r\n> 元素居中：`margin: auto;`\r\n>\r\n> 文本居中：`text-align: center;`\r\n>\r\n> 定位对齐：`position: absolute; right: 0px;`\r\n>\r\n> 将div使用overflow，使元素包括\r\n>\r\n> 垂直居中：`padding: 70px 0; text-align: center`\r\n\r\n## 选择\r\n\r\n> `div p{}`：选择div中所有p元素\r\n>\r\n> `div>p`：直接p元素\r\n>\r\n> `div+p`：div后的第一个p元素\r\n>\r\n> `div~p`：div后的所有p元素\r\n\r\n## 伪类\r\n\r\n```css\r\na:link {color:#FF0000;} /* 未访问的链接 */\r\na:visited {color:#00FF00;} /* 已访问的链接 */\r\na:hover {color:#FF00FF;} /* 鼠标划过链接 */\r\na:active {color:#0000FF;} /* 已选中的链接 */\r\n\r\na.red:visited {color:#FF0000;}\t/* 与class配合使用 */\r\n/* 匹配第一个子元素 */\r\np:first-child {}\r\n/* 匹配所有p中第一个<i>元素 */\r\np > i:first-child\r\n/* 匹配第一个p中所有<i>元素 */\r\np:first-child i\r\n```\r\n\r\n### 伪元素\r\n\r\n> `p:first-line`：p的第一行\r\n>\r\n> `h1:before `：h1之前\r\n>\r\n> `h1:after`：h1之后"}}]);